#include <stdio.h>
#include <stdlib.h>

long long gcd_ll(long long a, long long b) {
    while (b) { long long t = a % b; a = b; b = t; }
    return a;
}

int main() {
    int T; if (scanf("%d", &T)!=1) return 0;
    while (T--) {
        int N; scanf("%d", &N);
        long long *arr = (long long*)malloc(N * sizeof(long long));
        long long g = 0;
        for (int i = 0; i < N; ++i) {
            scanf("%lld", &arr[i]);
            g = (i==0) ? arr[i] : gcd_ll(g, arr[i]);
        }
        for (int i = 0; i < N; ++i) {
            if (i) printf(" ");
            printf("%lld", arr[i] / g);
        }
        printf("\n");
        free(arr);
    }
    return 0;
}

